            <button mat-icon-button (click)="back()">
              <mat-icon>arrow_back</mat-icon>
            </button>
            <h1>{{session.name | titlecase}}</h1>
          </div>
          <div>
            @if (isAdmin) {
              <button mat-raised-button color="warn" (click)="delete()">
                <mat-icon>delete</mat-icon>
                <span class="ml1">Delete</span>
